/// Sanitize and validate the request path to prevent path traversal attacks
fn sanitize_path(path: &str) -> Option<String> {
    // Reject paths with null bytes
    if path.contains('\0') {
        return None;
    }

    // Normalize the path
    let normalized = path
        .replace("\\", "/")
        .replace("//", "/");

    // Reject path traversal attempts
    if normalized.contains("../") || normalized.contains("/..") || normalized == ".." {
        return None;
    }

    // Reject excessively long paths
    if normalized.len() > 2048 {
        return None;
    }

    // Ensure path starts with /
    if !normalized.starts_with('/') {
        return None;
    }

    Some(normalized)
}

/// Validate request headers for security
fn validate_request_headers(req: &Request) -> Result<(), &'static str> {
    // Check for oversized headers
    let header_names: Vec<_> = req.get_header_names().collect();
    if header_names.len() > 100 {
        return Err("Too many request headers");
    }

    for name in &header_names {
        if let Some(value) = req.get_header(*name) {
            if value.len() > 8192 {
                return Err("Header value too large");
            }
        }
    }

    // Validate Host header exists
    if req.get_header(header::HOST).is_none() {
        return Err("Missing Host header");
    }

    Ok(())
}

