    #[test]
    fn test_sanitize_path_valid() {
        assert_eq!(sanitize_path("/api/v1/users"), Some("/api/v1/users".to_string()));
        assert_eq!(sanitize_path("/static/image.png"), Some("/static/image.png".to_string()));
        assert_eq!(sanitize_path("/"), Some("/".to_string()));
    }

